const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const REWARD_CLAIM_WINDOW_MS = 24 * 60 * 60 * 1000;

const players = new Map();
const levelConfigs = new Map([
  [1, { baseCoins: 100, baseGems: 1, targetScore: 500, targetTime: 120 }],
  [2, { baseCoins: 150, baseGems: 1, targetScore: 800, targetTime: 150 }],
  [3, { baseCoins: 200, baseGems: 2, targetScore: 1100, targetTime: 180 }],
  [4, { baseCoins: 250, baseGems: 2, targetScore: 1400, targetTime: 210 }],
  [5, { baseCoins: 300, baseGems: 3, targetScore: 1800, targetTime: 240 }]
]);

function getPlayer(playerId) {
  if (!players.has(playerId)) {
    players.set(playerId, {
      id: playerId,
      coins: 0,
      gems: 0,
      completedLevels: new Map(),
      pendingClaims: new Map()
    });
  }
  return players.get(playerId);
}

function now() {
  return Date.now();
}

function generateId() {
  return crypto.randomBytes(16).toString('hex');
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function calculateReward(levelNumber, score, timeTaken) {
  const config = levelConfigs.get(levelNumber) || {
    baseCoins: 50 * levelNumber,
    baseGems: Math.max(1, Math.floor(levelNumber / 3)),
    targetScore: 500 * levelNumber,
    targetTime: 120 + levelNumber * 30
  };

  const scoreRatio = config.targetScore > 0 ? score / config.targetScore : 0;
  const timeRatio = config.targetTime > 0 ? config.targetTime / Math.max(1, timeTaken) : 0;

  const performanceMultiplier = clamp((scoreRatio * 0.7) + (timeRatio * 0.3), 0.5, 2.5);

  const coins = Math.floor(config.baseCoins * performanceMultiplier);
  const gems = Math.floor(config.baseGems * clamp(performanceMultiplier, 0.75, 2));

  return {
    coins: Math.max(0, coins),
    gems: Math.max(0, gems),
    multiplier: performanceMultiplier
  };
}

function isValidCompletionInput(body) {
  return body &&
    typeof body.playerId === 'string' &&
    body.playerId.length > 0 &&
    Number.isInteger(body.levelNumber) &&
    body.levelNumber > 0 &&
    Number.isFinite(body.score) &&
    body.score >= 0 &&
    Number.isFinite(body.timeTaken) &&
    body.timeTaken > 0;
}

app.post('/api/levels/complete', (req, res) => {
  if (!isValidCompletionInput(req.body)) {
    return res.status(400).json({ error: 'Invalid completion payload' });
  }

  const { playerId, levelNumber, score, timeTaken } = req.body;
  const player = getPlayer(playerId);

  const reward = calculateReward(levelNumber, score, timeTaken);
  const claimId = generateId();
  const completedAt = now();

  player.pendingClaims.set(claimId, {
    claimId,
    levelNumber,
    score,
    timeTaken,
    reward,
    completedAt,
    expiresAt: completedAt + REWARD_CLAIM_WINDOW_MS,
    claimed: false
  });

  return res.json({
    success: true,
    claimId,
    levelNumber,
    rewardPreview: reward,
    claimExpiresAt: completedAt + REWARD_CLAIM_WINDOW_MS
  });
});

app.post('/api/rewards/claim', (req, res) => {
  const { playerId, claimId } = req.body || {};

  if (typeof playerId !== 'string' || !playerId || typeof claimId !== 'string' || !claimId) {
    return res.status(400).json({ error: 'Invalid claim payload' });
  }

  const player = getPlayer(playerId);
  const claim = player.pendingClaims.get(claimId);

  if (!claim) {
    return res.status(404).json({ error: 'Claim not found' });
  }

  if (claim.claimed) {
    return res.status(409).json({ error: 'Reward already claimed' });
  }

  if (now() > claim.expiresAt) {
    player.pendingClaims.delete(claimId);
    return res.status(410).json({ error: 'Claim expired' });
  }

  claim.claimed = true;
  player.coins += claim.reward.coins;
  player.gems += claim.reward.gems;

  player.completedLevels.set(claim.levelNumber, {
    levelNumber: claim.levelNumber,
    score: claim.score,
    timeTaken: claim.timeTaken,
    completedAt: claim.completedAt,
    reward: claim.reward
  });

  return res.json({
    success: true,
    playerId,
    balances: {
      coins: player.coins,
      gems: player.gems
    },
    claimedReward: {
      claimId,
      levelNumber: claim.levelNumber,
      reward: claim.reward
    }
  });
});

app.get('/api/player/:playerId', (req, res) => {
  const player = getPlayer(req.params.playerId);
  return res.json({
    playerId: player.id,
    balances: {
      coins: player.coins,
      gems: player.gems
    },
    completedLevels: Array.from(player.completedLevels.values()),
    pendingClaims: Array.from(player.pendingClaims.values()).map(({ claimed, ...rest }) => rest)
  });
});

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

app.listen(PORT, () => {
  console.log(`API listening on port ${PORT}`);
});